def store_info_in_header(
    info_type: str, info_content: str, header: Dict[str, str]
) -> Dict[str, str]:
    header_key_map = {
        'lang': 'Accept-Language',
        'encoding': 'Accept-Encoding',
        'cache': 'Cache-Control'
    }
    if info_type not in header_key_map:
        return header
    new_header = header.copy()
    new_header[header_key_map[info_type]] = info_content
    return new_header

